external_knowledge:
- A 'hotspot' refers to a country with a high frequency of incidents; 
- 'fallen' refers to people who have been killed (nkill); 
- 'wounded' refers to people who have been injured (nwound); 
- The term 'casualties' in this context encompasses both the number of people killed and wounded.

sql:
SELECT location_description, location_population, location_political_stability_index
FROM incident_locations
WHERE location_population > 5000;

SELECT location_description, location_population, location_political_stability_index
FROM incident_locations
WHERE location_id = 0;

SELECT targtype_name, targtype_description, AVG(targtype_prevalence) AS avg_prevalence
FROM target_types
GROUP BY targtype_name, targtype_description;

SELECT COUNT(incident_id) AS high_confidence_incidents
FROM incident_summaries
WHERE summary_confidence_level = 'high';

SELECT motive
FROM incident_motives
WHERE motive_id = 0;

SELECT incident_id, SUM(nkill + nwound) AS total_casualties
FROM incident_casualties
GROUP BY incident_id;

SELECT summary_text, summary_confidence_level
FROM incident_summaries
WHERE summary_confidence_level = 'high';

SELECT nkill, casualty_type
FROM incident_casualties
WHERE nkill > 0;

SELECT weaptype_name, weaptype_prevalence
FROM weapon_types
ORDER BY weaptype_prevalence DESC;

SELECT SUM(nkill + nwound) AS total_casualties
FROM incident_casualties
WHERE casualty_type = 'civilian';

SELECT attacktype_name, attacktype_prevalence
FROM attack_types
ORDER BY attacktype_prevalence DESC;

SELECT group_name
FROM terrorist_groups
WHERE group_id = 0;
